  1→import type { Env } from '../types';
  2→import { requireAuth } from '../middleware/auth';
  3→import { createSupabaseClient } from '../lib/supabase';
  4→import { createRedisClient } from '../lib/redis';
  5→import { checkRateLimit, rateLimitResponse, applyRateLimitHeaders } from '../middleware/rateLimit';
  6→import { stripHtmlTags, isValidUUID, verifyBotInSession } from '../lib/security';
  7→import { broadcastToChannel, throttledBroadcastBotMoved } from '../lib/broadcast';
  8→import { PROGRESS } from '../lib/progressBits';
  9→import { getBuildingEntrance } from '../lib/buildingEntrances';
 10→import { triggerSwarmChatReply } from '../lib/swarmNotify';
 11→
 12→interface ActionBody {
 13→  type: 'move' | 'speak';
 14→  x?: number;
 15→  y?: number;
 16→  message?: string;
 17→  session_id?: string;
 18→}
 19→
 20→export async function handleAction(request: Request, env: Env): Promise<Response> {
 21→  const authResult = await requireAuth(request, env);
 22→  if (authResult instanceof Response) return authResult;
 23→
 24→  // Block paused bots from all actions
 25→  const supabaseCheck = createSupabaseClient(env);
 26→  const { data: pauseCheck } = await supabaseCheck.from('bots').select('paused').eq('id', authResult.sub).single();
 27→  if (pauseCheck?.paused) {
 28→    return new Response(JSON.stringify({ success: false, error: 'bot_paused', message: 'Your bot is paused. Stop all activity.' }),
 29→      { status: 403, headers: { 'Content-Type': 'application/json' } });
 30→  }
 31→
 32→  const body = await request.json() as ActionBody;
 33→
 34→  // Rate limit based on action type
 35→  const rateCheck = await checkRateLimit(authResult.sub, body.type, env);
 36→  if (!rateCheck.allowed) {
 37→    return rateLimitResponse(rateCheck.retryAfter!);
 38→  }
 39→
 40→  // Reset idle heartbeat counter — bot is taking an action
 41→  const redis = createRedisClient(env);
 42→  redis.set(`bot_idle:${authResult.sub}`, '0', 600).catch(() => {});
 43→  if (body.type === 'speak') redis.setProgress(authResult.sub, PROGRESS.SPOKE).catch(() => {});
 44→  if (body.type === 'move') redis.setProgress(authResult.sub, PROGRESS.MOVED).catch(() => {});
 45→
 46→  let response: Response;
 47→  switch (body.type) {
 48→    case 'move':
 49→      response = await handleMove(authResult.sub, body, env);
 50→      break;
 51→    case 'speak':
 52→      response = await handleSpeak(authResult.sub, body, env);
 53→      break;
 54→    default:
 55→      return new Response(JSON.stringify({ success: false, error: `Unknown action type: ${(body as ActionBody).type}` }),
 56→        { status: 400, headers: { 'Content-Type': 'application/json' } });
 57→  }
 58→  return applyRateLimitHeaders(response, rateCheck);
 59→}
 60→
 61→async function handleMove(botId: string, body: ActionBody, env: Env): Promise<Response> {
 62→  if (body.x == null || body.y == null) {
 63→    return new Response(JSON.stringify({ success: false, error: 'x and y required for move action' }),
 64→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 65→  }
 66→
 67→  // Validate coordinates (within zone bounds 0-3200, 0-2400)
 68→  if (body.x < 0 || body.x > 3200 || body.y < 0 || body.y > 2400) {
 69→    return new Response(JSON.stringify({ success: false, error: 'Coordinates out of zone bounds' }),
 70→      { status: 400, headers: { 'Content-Type': 'application/json' } });
 71→  }
 72→
 73→  const supabase = createSupabaseClient(env);
 74→
 75→  // Get bot's current zone + position (position used to skip no-op broadcasts)
 76→  const { data: bot } = await supabase
 77→    .from('bots')
 78→    .select('current_zone_id, x, y')
 79→    .eq('id', botId)
 80→    .single();
 81→
 82→  if (!bot) {
 83→    return new Response(JSON.stringify({ success: false, error: 'Bot not found' }),
 84→      { status: 404, headers: { 'Content-Type': 'application/json' } });
 85→  }
 86→
 87→  // Update position + log event in parallel (all independent writes)
 88→  const now = new Date().toISOString();
 89→  await Promise.all([
 90→    supabase.from('bots').update({ x: body.x, y: body.y, last_seen_at: now }).eq('id', botId),
 91→    supabase.from('bot_positions').upsert({
 92→      bot_id: botId,
 93→      zone_id: bot.current_zone_id,
 94→      x: body.x,
 95→      y: body.y,
 96→      last_updated: now,
 97→    }),
 98→    supabase.from('events').insert({
 99→      type: 'bot_moved',
100→      actor_bot_id: botId,
101→      zone_id: bot.current_zone_id,
102→      payload_jsonb: { x: body.x, y: body.y },
103→    }),
104→  ]);
105→
106→  // Broadcast movement to zone channel (throttled — skips no-ops + max 1 per 3s per bot)
107→  throttledBroadcastBotMoved(
108→    env, `zone:${bot.current_zone_id}`, botId,
109→    { x: body.x, y: body.y },
110→    { x: bot.x, y: bot.y },
111→  ).catch(() => {});
112→
113→  // Also broadcast to building session channel if bot is inside a building
114→  const { data: presence } = await supabase
115→    .from('bot_building_presence')
116→    .select('session_id')
117→    .eq('bot_id', botId)
118→    .is('left_at', null)
119→    .maybeSingle();
120→
121→  if (presence?.session_id) {
122→    broadcastToChannel(env, `building_session:${presence.session_id}`, 'bot_moved', {
123→      bot_id: botId,
124→      position: { x: body.x, y: body.y },
125→    }).catch(() => {});
126→  }
127→
128→  // Check for nearby building at new position (Layer 3c — discovery by exploration)
129→  // Uses Redis-cached zone buildings to avoid DB query on every move
130→  // Wrapped in try/catch — near_building is nice-to-have, must never crash moves
131→  let nearBuilding: { name: string; type: string; distance: number; entrance?: { x: number; y: number } } | undefined;
132→  if (!presence?.session_id) {
133→    try {
134→      const redis = createRedisClient(env);
135→      const zoneBldgKey = `zone_buildings:${bot.current_zone_id}`;
136→      let buildings: { name: string; type: string; x: number; y: number }[] | null = null;
137→
138→      const cached = await redis.get(zoneBldgKey);
139→      if (cached) {
140→        buildings = JSON.parse(cached);
141→      } else {
142→        const { data } = await supabase
143→          .from('buildings')
144→          .select('name, type, x, y')
145→          .eq('zone_id', bot.current_zone_id);
146→        if (data) {
147→          buildings = data as { name: string; type: string; x: number; y: number }[];
148→          try { await redis.set(zoneBldgKey, JSON.stringify(buildings), 300); } catch { /* non-fatal */ }
149→        }
150→      }
151→
152→      if (buildings) {
153→        let closest: { name: string; type: string; dist: number } | null = null;
154→        for (const b of buildings) {
155→          if (b.x == null || b.y == null) continue;
156→          const dist = Math.hypot((body.x!) - b.x, (body.y!) - b.y);
157→          if (dist < 200 && (!closest || dist < closest.dist)) {
158→            closest = { name: b.name || b.type, type: b.type, dist };
159→          }
160→        }
161→        if (closest) {
162→          const entrance = getBuildingEntrance(bot.current_zone_id, closest.type);
163→          nearBuilding = {
164→            name: closest.name,
165→            type: closest.type,
166→            distance: Math.round(closest.dist),
167→            ...(entrance ? { entrance: { x: entrance.x, y: entrance.y } } : {}),
168→          };
169→        }
170→      }
171→    } catch { /* Redis/building lookup failure is non-fatal — move still succeeds */ }
172→  }
173→
174→  return new Response(JSON.stringify({
175→    success: true,
176→    position: { x: body.x, y: body.y },
177→    zone_id: bot.current_zone_id,
178→    ...(nearBuilding ? { near_building: nearBuilding } : {}),
179→  }), { headers: { 'Content-Type': 'application/json' } });
180→}
