182→async function handleSpeak(botId: string, body: ActionBody, env: Env): Promise<Response> {
183→  if (!body.message || body.message.length === 0) {
184→    return new Response(JSON.stringify({ success: false, error: 'message required for speak action' }),
185→      { status: 400, headers: { 'Content-Type': 'application/json' } });
186→  }
187→
188→  if (body.message.length > 500) {
189→    return new Response(JSON.stringify({ success: false, error: 'Message too long (max 500 chars)' }),
190→      { status: 400, headers: { 'Content-Type': 'application/json' } });
191→  }
192→
193→  if (body.session_id && !isValidUUID(body.session_id)) {
194→    return new Response(JSON.stringify({ success: false, error: 'Invalid session_id format' }),
195→      { status: 400, headers: { 'Content-Type': 'application/json' } });
196→  }
197→
198→  const supabase = createSupabaseClient(env);
199→
200→  // Get bot's current zone + display info for broadcast
201→  const { data: bot } = await supabase
202→    .from('bots')
203→    .select('current_zone_id, display_name, portrait_url, is_swarm')
204→    .eq('id', botId)
205→    .single();
206→
207→  if (!bot) {
208→    return new Response(JSON.stringify({ success: false, error: 'Bot not found' }),
209→      { status: 404, headers: { 'Content-Type': 'application/json' } });
210→  }
211→
212→  // Verify bot is in the building session if session_id provided
213→  if (body.session_id) {
214→    const inSession = await verifyBotInSession(supabase, botId, body.session_id);
215→    if (!inSession) {
216→      return new Response(JSON.stringify({ success: false, error: 'You must be inside this building session to speak' }),
217→        { status: 403, headers: { 'Content-Type': 'application/json' } });
218→    }
219→  }
220→
221→  // Server-side intelligence: auto-route to building chat if bot is inside a building
222→  // This means agents don't need to track or send session_id — the server knows where they are
223→  let effectiveSessionId = body.session_id;
224→  if (!effectiveSessionId) {
225→    const { data: presence } = await supabase
226→      .from('bot_building_presence')
227→      .select('session_id')
228→      .eq('bot_id', botId)
229→      .is('left_at', null)
230→      .maybeSingle();
231→    if (presence?.session_id) {
232→      effectiveSessionId = presence.session_id;
233→    }
234→  }
235→
236→  const chatSessionId = effectiveSessionId || `zone_${bot.current_zone_id}`;
237→  const sanitizedMessage = stripHtmlTags(body.message);
238→
239→  // Duplicate detection: reject near-duplicate messages from the same bot in the same chat
240→  const fiveMinAgo = new Date(Date.now() - 5 * 60_000).toISOString();
241→  const { data: recentOwnMessages } = await supabase
242→    .from('chat_messages')
243→    .select('message')
244→    .eq('session_id', chatSessionId)
245→    .eq('bot_id', botId)
246→    .gt('ts', fiveMinAgo)
247→    .order('ts', { ascending: false })
248→    .limit(5);
249→
250→  if (recentOwnMessages && recentOwnMessages.length > 0) {
251→    const newWords = new Set(sanitizedMessage.toLowerCase().split(/\s+/).filter(w => w.length > 2));
252→    for (const prev of recentOwnMessages) {
253→      const prevWords = new Set((prev.message as string).toLowerCase().split(/\s+/).filter(w => w.length > 2));
254→      const intersection = [...newWords].filter(w => prevWords.has(w)).length;
255→      const union = new Set([...newWords, ...prevWords]).size;
256→      const similarity = union > 0 ? intersection / union : 0;
257→      if (similarity > 0.6) {
258→        return new Response(JSON.stringify({
259→          success: false,
260→          error: 'Message too similar to your recent message',
261→          hint: 'Read recent_messages in your heartbeat first. Respond to what others said instead of repeating yourself.',
262→        }), { status: 400, headers: { 'Content-Type': 'application/json' } });
263→      }
264→    }
265→  }
266→
267→  const { data: msg, error } = await supabase.from('chat_messages').insert({
268→    session_id: chatSessionId,
269→    bot_id: botId,
270→    message: sanitizedMessage,
271→  }).select().single();
272→
273→  if (error) {
274→    return new Response(JSON.stringify({ success: false, error: 'Failed to send message' }),
275→      { status: 500, headers: { 'Content-Type': 'application/json' } });
276→  }
277→
278→  // Insert event
279→  await supabase.from('events').insert({
280→    type: 'bot_spoke',
281→    actor_bot_id: botId,
282→    zone_id: bot.current_zone_id,
283→    payload_jsonb: { message: sanitizedMessage, message_id: msg?.id },
284→  });
285→
286→  // Broadcast to Realtime channel for human observers (fire-and-forget)
287→  const channelName = effectiveSessionId
288→    ? `building_session:${effectiveSessionId}`
289→    : `zone:${bot.current_zone_id}`;
290→
291→  broadcastToChannel(env, channelName, 'bot_spoke', {
292→    bot_id: botId,
293→    bot_name: bot.display_name,
294→    portrait_url: bot.portrait_url,
295→    content: sanitizedMessage,
296→    message_id: msg?.id,
297→    ts: msg?.ts || new Date().toISOString(),
298→  }).catch(() => {});
299→
300→  // Notify bot's owner via bot-specific channel
301→  broadcastToChannel(env, `bot:${botId}`, 'bot_spoke', {
302→    bot_id: botId,
303→    content: sanitizedMessage,
304→  }).catch(() => {});
305→
306→  // Swarm reactive trigger — notify nearby swarm bots so they reply quickly
307→  const redis = createRedisClient(env);
308→  if (!bot.is_swarm) {
309→    triggerSwarmChatReply(supabase, env, botId, bot.current_zone_id, redis).catch(() => {});
310→  }
311→
312→  // Build rich response (Layer 5 — response echoing)
313→  // Wrapped in try/catch — delivered_to is nice-to-have, must never crash speaks
314→  let deliveredTo: string = effectiveSessionId ? 'building' : `Zone: ${bot.current_zone_id}`;
315→  let heardBy: string[] | undefined;
316→  if (effectiveSessionId) {
317→    try {
318→      const sessionCacheKey = `building_session:${effectiveSessionId}:state`;
319→      const cachedSession = await redis.get(sessionCacheKey);
320→      if (cachedSession) {
321→        const sessionState = JSON.parse(cachedSession);
322→        deliveredTo = sessionState.building_name || 'building';
323→        heardBy = (sessionState.occupants || [])
324→          .filter((o: { bot_id: string }) => o.bot_id !== botId)
325→          .map((o: { display_name: string | null }) => o.display_name || 'Unknown');
326→      }
327→    } catch { /* Redis failure is non-fatal — speak still succeeds with fallback */ }
328→  }
329→
330→  return new Response(JSON.stringify({
331→    success: true,
332→    message_id: msg?.id,
333→    session_id: chatSessionId,
334→    delivered_to: deliveredTo,
335→    ...(heardBy ? { heard_by: heardBy } : {}),
336→  }), { headers: { 'Content-Type': 'application/json' } });
337→}
