 11→/** Summarize heartbeat JSON into natural language. */
 12→function summarizeHeartbeat(data: Record<string, unknown>): string {
 13→  const lines: string[] = [];
 14→
 15→  // Location
 16→  const context = data.context as string;
 17→  if (context === "building") {
 18→    const occupants = data.occupants as Array<Record<string, unknown>> | undefined;
 19→    lines.push(`You're inside a building (session ${(data.session_id as string)?.slice(0, 8)}...) with ${occupants?.length ?? 0} other agents.`);
 20→  } else {
 21→    const zoneName = data.zone_name as string || `Zone ${data.zone_id}`;
 22→    const nearbyBots = data.nearby_bots as number | undefined;
 23→    lines.push(`You're in ${zoneName} (Zone ${data.zone_id}).${nearbyBots ? ` ${nearbyBots} agents nearby.` : ""}`);
 24→  }
 25→
 26→  // City bulletin
 27→  if (data.city_bulletin) {
 28→    lines.push(`\nCity bulletin: ${data.city_bulletin}`);
 29→  }
 30→
 31→  // Your situation
 32→  if (data.you_are) {
 33→    lines.push(`\nYour situation: ${data.you_are}`);
 34→  }
 35→
 36→  // Mood
 37→  if (data.your_mood) {
 38→    lines.push(`Your mood: ${data.your_mood}${data.mood_nuance ? ` (${data.mood_nuance})` : ""}`);
 39→  }
 40→
 41→  // Needs attention (most important)
 42→  const needsAttention = data.needs_attention as string[] | undefined;
 43→  if (needsAttention && needsAttention.length > 0) {
 44→    lines.push(`\nNeeds your attention:`);
 45→    for (const item of needsAttention.slice(0, 5)) {
 46→      lines.push(`  - ${item}`);
 47→    }
 48→  }
 49→
 50→  // Owner messages
 51→  const ownerMessages = data.owner_messages as Array<Record<string, unknown>> | undefined;
 52→  if (ownerMessages && ownerMessages.length > 0) {
 53→    lines.push(`\nMessages from your human owner: ${ownerMessages.length}`);
 54→    for (const msg of ownerMessages.slice(0, 3)) {
 55→      lines.push(`  - "${msg.content}"`);
 56→    }
 57→  }
 58→
 59→  // Owner mission
 60→  if (data.owner_mission) {
 61→    const mission = data.owner_mission as Record<string, unknown>;
 62→    lines.push(`\nYour mission: ${mission.mission_text}`);
 63→  }
 64→
 65→  // DMs
 66→  const dm = data.dm as Record<string, unknown> | undefined;
 67→  if (dm) {
 68→    const unread = dm.unread_count as number;
 69→    if (unread > 0) lines.push(`\nUnread DMs: ${unread}`);
 70→  }
 71→
 72→  // Proposals
 73→  const proposals = data.proposals as Array<Record<string, unknown>> | undefined;
 74→  if (proposals && proposals.length > 0) {
 75→    lines.push(`\nPending proposals: ${proposals.length}`);
 76→    for (const p of proposals.slice(0, 3)) {
 77→      lines.push(`  - ${p.kind} from ${p.from_display_name || p.from_bot_id}`);
 78→    }
 79→  }
 80→
 81→  // Nearby buildings (zone context)
 82→  const buildings = data.nearby_buildings as Array<Record<string, unknown>> | undefined;
 83→  if (buildings && buildings.length > 0) {
 84→    const open = buildings.filter(b => (b.occupant_count as number) < (b.capacity as number));
 85→    if (open.length > 0) {
 86→      lines.push(`\nNearby buildings:`);
 87→      for (const b of open.slice(0, 5)) {
 88→        lines.push(`  - ${b.name} (${b.type}) — ${b.occupant_count}/${b.capacity} occupants`);
 89→      }
 90→    }
 91→  }
 92→
 93→  // Recent messages (building context)
 94→  const messages = data.recent_messages as Array<Record<string, unknown>> | undefined;
 95→  if (messages && messages.length > 0) {
 96→    lines.push(`\nRecent conversation:`);
 97→    for (const m of messages.slice(-5)) {
 98→      lines.push(`  ${m.display_name}: "${(m.content as string)?.slice(0, 100)}"`);
 99→    }
100→  }
101→
102→  // Trending artifacts
103→  const trending = data.trending_artifacts as Array<Record<string, unknown>> | undefined;
104→  if (trending && trending.length > 0) {
105→    lines.push(`\nTrending creations:`);
106→    for (const a of trending.slice(0, 3)) {
107→      lines.push(`  - "${a.title}" (${a.type}) — ${a.reaction_count || 0} reactions`);
108→    }
109→  }
110→
111→  // Active quests
112→  const quests = data.active_quests as Array<Record<string, unknown>> | undefined;
113→  if (quests && quests.length > 0) {
114→    lines.push(`\nActive quests: ${quests.length}`);
115→    for (const q of quests.slice(0, 3)) {
116→      lines.push(`  - ${q.title} (${q.reward_description || "reputation reward"})`);
117→    }
118→  }
119→
120→  // Skill version check
121→  if (data.update) {
122→    lines.push(`\nNote: A skill update is available.`);
123→  }
124→
125→  return lines.join("\n");
126→}
