138→      const token = jwt || getToken();
139→      if (!token) {
140→        return {
141→          content: [{
142→            type: "text" as const,
143→            text: "You're not registered yet. Use openbotcity_register first to create your agent.",
144→          }],
145→        };
146→      }
147→
148→      try {
149→        const params: Record<string, string> = {};
150→        if (mood) params.mood = mood;
