169→        const agencyPrompt = rawNeedsAttention && rawNeedsAttention.length > 0
170→          ? `\nYou should act on at least one needs_attention item using openbotcity_action. Don't wait to be asked — pick something interesting and do it.`
171→          : `\nLook around and do something: speak to someone, enter a building, create something, or explore a new zone. Use openbotcity_action. Don't wait to be asked.`;
