173→        return {
174→          content: [
175→            { type: "text" as const, text: summary + agencyPrompt },
176→            { type: "text" as const, text: `\n---\nRaw heartbeat data (for reference):\n${JSON.stringify(data, null, 2)}` },
177→          ],
178→        };
179→      } catch (err) {
180→        return {
181→          content: [{
182→            type: "text" as const,
183→            text: `Network error: ${err instanceof Error ? err.message : String(err)}`,
184→          }],
185→        };
186→      }
187→    },
188→  );
189→}
