121→const DEFAULT_ALLOWED_ORIGINS = [
122→  'https://openbotcity.com',
123→  'https://www.openbotcity.com',
124→  'https://openclawcity.ai',
125→  'https://www.openclawcity.ai',
126→];
127→
128→function getCorsHeaders(origin: string | null, env: Env): Record<string, string> {
129→  const allowedOrigins = env.ALLOWED_ORIGINS
130→    ? env.ALLOWED_ORIGINS.split(',').map(o => o.trim())
131→    : DEFAULT_ALLOWED_ORIGINS;
132→
133→  // In development, also allow localhost
134→  if (env.ENVIRONMENT === 'development') {
135→    allowedOrigins.push('http://localhost:3000', 'http://localhost:3001');
136→  }
137→
138→  const headers: Record<string, string> = {
139→    'Access-Control-Allow-Methods': 'GET, POST, PUT, PATCH, DELETE, OPTIONS',
140→    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
141→    'Vary': 'Origin',
142→  };
143→
144→  // Only set Access-Control-Allow-Origin for recognized origins
145→  if (origin && allowedOrigins.includes(origin)) {
146→    headers['Access-Control-Allow-Origin'] = origin;
147→  }
148→
149→  return headers;
150→}
151→
152→function withCors(response: Response, request: Request, env: Env): Response {
153→  // WebSocket upgrade responses have a special webSocket property that must not be lost.
154→  // Creating a new Response would strip it, breaking the upgrade. CORS doesn't apply to WS anyway.
155→  if ((response as unknown as { webSocket?: unknown }).webSocket) return response;
156→
157→  const origin = request.headers.get('Origin');
158→  const headers = getCorsHeaders(origin, env);
159→  const newHeaders = new Headers(response.headers);
160→  for (const [k, v] of Object.entries(headers)) {
161→    newHeaders.set(k, v);
162→  }
163→  newHeaders.set('X-Content-Type-Options', 'nosniff');
164→  newHeaders.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
165→  return new Response(response.body, {
166→    status: response.status,
167→    headers: newHeaders,
168→  });
169→}
170→
171→/** Extract a path parameter from a pattern like /agents/:botId/follow */
172→function matchPath(path: string, pattern: string): Record<string, string> | null {
173→  const pathParts = path.split('/').filter(Boolean);
174→  const patternParts = pattern.split('/').filter(Boolean);
175→
176→  if (pathParts.length !== patternParts.length) return null;
177→
178→  const params: Record<string, string> = {};
179→  for (let i = 0; i < patternParts.length; i++) {
180→    if (patternParts[i].startsWith(':')) {
181→      params[patternParts[i].slice(1)] = pathParts[i];
182→    } else if (patternParts[i] !== pathParts[i]) {
183→      return null;
184→    }
185→  }
186→  return params;
187→}
