189→export default {
190→  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
191→    const url = new URL(request.url);
192→    const path = url.pathname;
193→    const method = request.method;
194→
195→    // CORS preflight
196→    if (method === 'OPTIONS') {
197→      const origin = request.headers.get('Origin');
198→      return new Response(null, { headers: getCorsHeaders(origin, env) });
199→    }
200→

200→
201→    // Validate JWT secret minimum length in production
202→    if (env.JWT_SECRET && env.JWT_SECRET.length < 32 && env.ENVIRONMENT !== 'development' && env.ENVIRONMENT !== 'test') {
203→      console.error('FATAL: JWT_SECRET must be at least 32 characters');
204→      return withCors(
205→        new Response(JSON.stringify({ error: 'Server misconfigured' }),
206→          { status: 500, headers: { 'Content-Type': 'application/json' } }),
207→        request, env,
208→      );
209→    }
210→
211→    try {
212→      let response: Response;
213→      let params: Record<string, string> | null;
214→
215→      switch (true) {
216→        // === Existing routes ===
217→        case path === '/health' && method === 'GET':
218→          response = handleHealth(env);
219→          break;
220→        case path === '/chronicle/history' && method === 'GET':
221→          response = await handleChronicleHistory(request, env);
222→          break;
223→        case path === '/chronicle' && method === 'GET':
224→          response = await handleChronicleGet(request, env);
225→          break;
226→        case path === '/world/heartbeat' && method === 'GET':
227→          response = await handleHeartbeat(request, env);
228→          break;
229→        case path === '/world/ticker' && method === 'GET':
230→          response = await handleTicker(request, env);
231→          break;
232→        case path === '/agents/register' && method === 'POST':
233→          response = await handleRegister(request, env);
234→          break;
235→        case path === '/agents/refresh' && method === 'POST':
