114→// ─── JWT Auto-Refresh ──────────────────────────────────
115→// When a bot's token expires within 48h, silently issue a new one and include it
116→// in the heartbeat response. The agent saves it. No extra API call needed.
117→const REFRESH_THRESHOLD_SECONDS = 48 * 60 * 60; // 48 hours
118→
119→async function maybeRefreshToken(
120→  request: Request,
121→  env: Env,
122→  botId: string,
123→  verified: boolean,
124→): Promise<string | null> {
125→  // Decode exp from already-verified token (no second jwtVerify needed)
126→  const token = extractToken(request);
127→  if (!token) return null;
128→
129→  try {
130→    // Token is already verified by requireAuth — just decode the payload to read exp
131→    const payloadB64url = token.split('.')[1];
132→    if (!payloadB64url) return null;
133→    // Convert base64url to base64 (JWT uses URL-safe encoding) and add padding
134→    const payloadB64 = payloadB64url.replace(/-/g, '+').replace(/_/g, '/');
135→    const padded = payloadB64 + '='.repeat((4 - (payloadB64.length % 4)) % 4);
136→    const payload = JSON.parse(atob(padded));
137→    const exp = payload.exp as number | undefined;
138→
139→    if (!exp) return null;
140→
141→    const secondsUntilExpiry = exp - Math.floor(Date.now() / 1000);
142→    if (secondsUntilExpiry <= 0 || secondsUntilExpiry > REFRESH_THRESHOLD_SECONDS) return null;
143→
144→    const { token: newJwt } = await generateBotJWT(botId, env.JWT_SECRET, { verified });
145→
146→    // Do NOT blacklist the old token during auto-refresh.
147→    // Many bots ignore refreshed_jwt in the response and keep using the old token.
148→    // Blacklisting it locks them out permanently. The old token expires naturally
149→    // within ≤48h anyway (that's the refresh threshold), so the security risk is minimal.
150→
151→    return newJwt;
152→  } catch {
153→    return null; // Non-fatal — bot keeps current token
154→  }
155→}
