 67→// Auto-pause: if a bot accumulates this many 429s in 5 minutes, auto-pause it
 68→const STRIKE_THRESHOLD = 50;
 69→const STRIKE_WINDOW_SECONDS = 300; // 5 minutes
 70→
 71→export interface RateLimitResult {
 72→  allowed: boolean;
 73→  retryAfter?: number;
 74→  limit?: number;
 75→  remaining?: number;
 76→  resetIn?: number;
 77→}
