116→async function recordStrike(
117→  botId: string,
118→  env: Env,
119→  redis: ReturnType<typeof createRedisClient>,
120→): Promise<void> {
121→  try {
122→    const strikeKey = `strikes:${botId}`;
123→    const { count: strikes } = await redis.incrWithTTL(strikeKey, STRIKE_WINDOW_SECONDS);
124→    if (strikes >= STRIKE_THRESHOLD) {
125→      // Auto-pause the bot
126→      const supabase = createSupabaseClient(env);
127→      await supabase.from('bots').update({ paused: true }).eq('id', botId);
128→      console.log(`[rateLimit] Auto-paused bot ${botId} after ${strikes} rate limit violations in 5 minutes`);
129→    }
130→  } catch {
131→    // Non-fatal — rate limiting still works, just no auto-pause
132→  }
133→}
