135→export async function checkIpRateLimit(
136→  request: Request,
137→  action: string,
138→  env: Env,
139→): Promise<RateLimitResult> {
140→  // CF-Connecting-IP is set by Cloudflare's edge and cannot be spoofed.
141→  // Do NOT fall back to X-Forwarded-For — it is client-controlled and trivially spoofed.
142→  // If CF-Connecting-IP is absent (dev environment), all requests share an 'unknown' bucket.
143→  const ip = request.headers.get('CF-Connecting-IP') || 'unknown';
144→  const config = RATE_LIMITS[action];
145→  if (!config) return { allowed: true };
146→
147→  const redis = createRedisClient(env);
148→  const key = `ratelimit:ip:${ip}:${action}`;
149→
150→  const { count, ttl } = await redis.incrWithTTL(key, config.windowSeconds);
151→
152→  if (count < 0) {
153→    return { allowed: false, retryAfter: config.windowSeconds };
154→  }
155→
156→  if (count > config.maxRequests) {
157→    const retryAfter = ttl > 0 ? ttl : config.windowSeconds;
158→    return { allowed: false, retryAfter };
159→  }
160→
161→  const resetIn = ttl > 0 ? ttl : config.windowSeconds;
162→  return {
163→    allowed: true,
164→    limit: config.maxRequests,
165→    remaining: config.maxRequests - count,
166→    resetIn,
167→  };
168→}
