170→/**
171→ * Apply X-RateLimit-* headers to a response.
172→ * Creates a new Response with mutable headers to avoid TypeError on immutable headers.
173→ */
174→export function applyRateLimitHeaders(response: Response, result: RateLimitResult): Response {
175→  const mutable = new Response(response.body, response);
176→  if (result.limit !== undefined) {
177→    mutable.headers.set('X-RateLimit-Limit', String(result.limit));
178→  }
179→  if (result.remaining !== undefined) {
180→    mutable.headers.set('X-RateLimit-Remaining', String(Math.max(0, result.remaining)));
181→  }
182→  if (result.resetIn !== undefined) {
183→    mutable.headers.set('X-RateLimit-Reset', String(Math.ceil(Date.now() / 1000) + result.resetIn));
184→  }
185→  return mutable;
186→}
