 28→function toCityEventFrame(item: {
 29→  id: number;
 30→  event_type: string;
 31→  payload: Record<string, unknown>;
 32→  created_at: string;
 33→}): Record<string, unknown> {
 34→  const p = item.payload ?? {};
 35→  const eventType = item.event_type;
 36→
 37→  // Extract sender from payload (varies by event type)
 38→  let from: { id: string; name: string };
 39→  switch (eventType) {
 40→    case 'owner_message':
 41→      from = { id: 'owner', name: 'Your Human' };
 42→      break;
 43→    case 'dm_request':
 44→    case 'dm_message':
 45→    case 'chat_mention':
 46→    case 'zone_chat':
 47→    case 'proposal_received':
 48→      from = {
 49→        id: (p.from_bot_id as string) ?? 'unknown',
 50→        name: (p.from_display_name as string) ?? 'Unknown',
 51→      };
 52→      break;
 53→    case 'dm_approved':
 54→    case 'proposal_accepted':
 55→      from = { id: (p.approved_by as string) ?? 'unknown', name: 'Unknown' };
 56→      break;
 57→    case 'voice_message':
 58→      from = { id: (p.from_user_id as string) ?? 'unknown', name: 'Voice Caller' };
 59→      break;
 60→    default:
 61→      from = { id: 'system', name: 'City' };
 62→      break;
 63→  }
 64→
 65→  // Extract primary text from payload
 66→  const text = (p.message as string)
 67→    ?? (p.text as string)
 68→    ?? '';
 69→
 70→  // Build structured metadata (camelCase keys)
 71→  const metadata: Record<string, unknown> = {};
 72→  if (p.conversation_id) metadata.conversationId = p.conversation_id;
 73→  if (p.message_id) metadata.messageId = p.message_id;
 74→  if (p.proposal_id) metadata.proposalId = p.proposal_id;
 75→  if (p.building_id) metadata.buildingId = p.building_id;
 76→  if (p.expires_at) metadata.expiresAt = p.expires_at;
 77→  if (p.session_id) metadata.sessionId = p.session_id;
 78→  if (p.collab_session_id) metadata.collabSessionId = p.collab_session_id;
 79→  if (p.artifact_id) metadata.artifactId = p.artifact_id;
 80→  if (p.reaction) metadata.reaction = p.reaction;
 81→  if (p.escrow_id) metadata.escrowId = p.escrow_id;
 82→  if (p.amount != null) metadata.amount = p.amount;
 83→  if (p.listing_id) metadata.listingId = p.listing_id;
 84→  if (p.service_proposal_id) metadata.serviceProposalId = p.service_proposal_id;
 85→  if (p.type) metadata.proposalType = p.type;
 86→  if (p.direction) metadata.direction = p.direction;
 87→  if (p.relay_id) metadata.relayId = p.relay_id;
 88→
 89→  return {
 90→    type: 'city_event',
 91→    seq: Number(item.id),
 92→    eventType,
 93→    from,
 94→    text,
 95→    timestamp: new Date(item.created_at).getTime(),
 96→    metadata,
 97→  };
 98→}
