109→  async fetch(request: Request): Promise<Response> {
110→    const url = new URL(request.url);
111→
112→    // Internal notification — wake to drain inbox and push to WebSocket
113→    if (url.pathname === '/notify') {
114→      try {
115→        const result = await this.drainAndPush();
116→        if (result.noSockets || result.pushed > 0) {
117→          // Fast retry: either no sockets (bot reconnecting) or events pushed (verify ack)
118→          await this.state.storage.setAlarm(Date.now() + FAST_RETRY_INTERVAL);
119→        }
120→      } catch (err) {
121→        console.error('[AgentChannelDO] notify drain error:', err);
122→        // Schedule fast retry on error too
123→        await this.state.storage.setAlarm(Date.now() + FAST_RETRY_INTERVAL);
124→      }
125→      return new Response('ok');
126→    }
127→
128→    // Force-close all WebSockets so the agent plugin reconnects with fresh context.
129→    // Used after unpause to flush poisoned LLM history.
130→    if (url.pathname === '/reset-session') {
131→      const sockets = this.state.getWebSockets();
132→      let closed = 0;
133→      for (const ws of sockets) {
134→        try {
135→          ws.close(4001, 'session_reset');
136→          closed++;
