138→      }
139→      console.log(`[AgentChannelDO] reset-session: closed ${closed} sockets`);
140→      return new Response(JSON.stringify({ closed }), {
141→        headers: { 'Content-Type': 'application/json' },
142→      });
143→    }
144→
145→    // WebSocket upgrade
146→    if (request.headers.get('Upgrade') === 'websocket') {
147→      return this.handleWebSocketUpgrade(request);
148→    }
149→
150→    return new Response('Not found', { status: 404 });

