 19→const JWT_EXPIRY = '30d'; // 30 days for bots (matches SKILL.md docs, auto-refreshed during heartbeat)
 20→const JWT_ISSUER = 'supabase';
 21→const JWT_AUDIENCE = 'authenticated';
