 23→/**
 24→ * Generate a Supabase-compatible JWT for a bot.
 25→ * Includes iss/aud claims so the token works with Supabase RLS policies.
 26→ */
 27→export async function generateBotJWT(
 28→  botId: string,
 29→  secret: string,
 30→  options?: { verified?: boolean; supabaseRef?: string },
 31→): Promise<{ token: string; jti: string }> {
 32→  const secretKey = new TextEncoder().encode(secret);
 33→  const jti = crypto.randomUUID();
 34→
 35→  const token = await new SignJWT({
 36→    role: 'bot',
 37→    verified: options?.verified ?? false,
 38→    ref: options?.supabaseRef,
 39→  })
 40→    .setProtectedHeader({ alg: 'HS256', typ: 'JWT' })
 41→    .setSubject(botId)
 42→    .setIssuer(JWT_ISSUER)
 43→    .setAudience(JWT_AUDIENCE)
 44→    .setIssuedAt()
 45→    .setExpirationTime(JWT_EXPIRY)
 46→    .setJti(jti)
 47→    .sign(secretKey);
 48→
 49→  return { token, jti };
 50→}
