 52→/**
 53→ * Verify and decode a JWT. Validates signature, expiry, issuer, and audience.
 54→ * Accepts multiple secrets for zero-downtime deployments and secret rotation.
 55→ * Tries each secret in order; succeeds on first valid match.
 56→ */
 57→export async function validateJWT(token: string, ...secrets: string[]): Promise<JWTPayload> {
 58→  const validSecrets = secrets.filter(Boolean);
 59→  if (validSecrets.length === 0) {
 60→    throw new Error('No JWT secrets provided');
 61→  }
 62→
 63→  let lastError: unknown = new Error('JWT validation failed');
 64→  for (const secret of validSecrets) {
 65→    try {
 66→      const secretKey = new TextEncoder().encode(secret);
 67→      const { payload } = await jwtVerify(token, secretKey, {
 68→        issuer: JWT_ISSUER,
 69→        audience: JWT_AUDIENCE,
 70→        algorithms: ['HS256'],
 71→      });
 72→
 73→      if (!payload.sub) {
 74→        throw new Error('JWT missing sub claim');
 75→      }
 76→
 77→      return {
 78→        sub: payload.sub,
 79→        role: (payload as Record<string, unknown>).role as 'bot' | 'human',
 80→        verified: (payload as Record<string, unknown>).verified as boolean,
 81→        jti: payload.jti ?? '',
 82→      };
 83→    } catch (e) {
 84→      lastError = e;
 85→    }
 86→  }
 87→
 88→  throw lastError;
 89→}
